export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:40。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "禮堂直播控制區。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這裡是禮堂後方的一間窄小的控制室。三面牆上是螢幕——閉幕倒數的計時器、舞台主鏡頭的信號、備份線路的狀態燈。地上纏滿線材。空氣裡是設備散熱的焦味和潮濕電纜的塑膠味。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "控制室裡的直播志工被韓越以「側台要人手」叫走了。只剩一個備份素材線的空接口。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠從背心內側取出母親的舊記憶卡。她的手指很穩。她把記憶卡插進連接備份線的讀卡機。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕亮了。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個檔案目錄展開在黑色的背景上。顧言看到一長串檔名——大部分是圖片縮圖和音訊片段。但最上面三個檔案是紅色的。鎖住的。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "能播的在下面。照片、錄音片段、火災前後的日期。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "但這三個——", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她指了指最上面紅色的三個。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "工程付款紀錄。材料驗收單。還有一段完整的錄音。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "這三個是全部證據鏈的核心。沒有它們，下面的照片和片段只是「可疑」。有了它們——才是「證據」。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "密碼。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）密碼。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）13:20。她提過。最關鍵的檔案打不開。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我以為基座底板裡會有。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠從口袋裡掏出剛才從林主任那裡記下的底板夾層內容——她沒能拿到實物，但她拍到了資料夾的標籤和部分可見的文字。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "底板裡的東西，我看到了標籤。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "是工程付款的副本。但不是密碼。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "密碼不藏在那裡。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "那密碼在哪？", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你父親設的。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "我母親的記憶卡。你父親加密的。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "他不可能把密碼寫在基座裡——那太容易被找到。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "他會藏在只有他能驗證的地方。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著顧言。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯什麼？", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "密碼可能在你身上。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "不是寫在你身上。是——你知道某件事。你記得某個東西。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你父親會把密碼藏在一個只有你記得的地方。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言盯著螢幕上那三個紅色的檔案。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯我。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）密碼在我記得的地方。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我⋯⋯", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我記得什麼？", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他閉上眼睛。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨聲變遠了。控制室的風扇聲變遠了。許星棠的呼吸聲變遠了。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他往回找。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "往很遠很遠的地方找。十年前。七歲。火災那天之前。火災那天。那些他一直不願意碰的、碎成渣的記憶。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "有什麼在那裡。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是畫面。是聲音。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個聲音——", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.FemaleVoice, character: "女聲", dialogue: "孩子看見了。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的呼吸停了一拍。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯那是誰的聲音。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不是媽媽。不是外婆。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是一個女人。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在說——「孩子看見了。」", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "畫面回來了。不是完整的。是一片一片的。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "濕的地面。水的反光。很暗的走廊。有人跑。有東西在燒——不是眼前燒，是空氣裡那種焦的、辣的、嗆的味道，從很遠的地方飄過來。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後——一雙手。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是抓他。是蓋他。一件外套——濕的、重的、帶著煙味和一種他後來再也聞不到的洗衣粉味道的外套——從頭頂蓋下來。把他整個人裹住了。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯爸爸。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）爸爸把我蓋住了。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）他在說什麼。他在說——", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個聲音。父親的聲音。低的、急的、壓在他耳朵旁邊的——", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但話斷了。只有前兩個字是清楚的。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「不要只⋯⋯」", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "後面的字被另一個聲音蓋掉了。不是雨聲。是快門聲。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "咔嚓。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的記憶裡出現了一個畫面——從外套的縫隙裡看出去。一個女人。低馬尾。手裡舉著相機。鏡頭對著他。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯相機。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）那個女人——拿著相機——", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在拍。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她在拍什麼？", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "記憶又碎了。那個女人的臉他想不起來。她拍到了什麼他也不知道。她放下相機之後做了什麼——全沒了。像一段被剪掉的膠卷。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "只剩下三塊碎片。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「孩子看見了。」", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "父親的濕外套。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「不要只⋯⋯」", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不要只⋯⋯什麼？", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）不要只什麼——", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）後面是什麼——", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他想不起來。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他用盡力氣往那個方向找。往那團黑裡找。但記憶像水——他越用力抓，它越從指縫裡漏掉。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯想不起來。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）差一個字。就差一個。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）「不要只⋯⋯」", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）後面是什麼？", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他睜開眼睛。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "控制室的螢幕還亮著。三個紅色的檔案安靜地鎖在那裡。密碼輸入框的光標一閃一閃，在等他輸入。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他什麼也輸不了。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯我記得「不要只」。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "但後面——", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "後面沒了。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看向許星棠。他知道她在等。他知道如果他能想起來，這三個檔案就能打開，全部的證據鏈就能完整地送進直播備份線，在 23:00 閉幕切換的那一刻——", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他想不起來。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看著他。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有催。沒有嘆氣。沒有皺眉。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她只是看著他。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你父親把密碼藏在你身上。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "不是因為你能想起來。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "是因為——只有你在的時候，密碼才是活的。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你現在想起一半。那說明它在那裡。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "只是還沒有到打開的時候。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "如果不打開——", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "那就先把能播的播出去。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的手指在螢幕上劃過那些沒有鎖住的檔案。火災前後的照片。錄音的片段——「南翼」「材料」「先把資料拿走」——零碎的、被截斷的、沒有上下文的句子。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "這些能播。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "但只有這些——", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她停了一下。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "不夠定罪。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "只夠造成混亂。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言看著螢幕。那些能播放的片段——照片、錄音——它們是真的。它們證明十年前有人在做不對的事。但它們不完整。沒有付款紀錄，沒有驗收單，沒有那段完整的錄音，它們就是一盤散在地上的拼圖碎片。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "足以讓所有人停下來看。不足以讓所有人看清。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯不夠。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）能播的不夠。鎖住的打不開。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我手裡有鑰匙的一半。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）「不要只⋯⋯」", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）另一個半——", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）想不起來。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:48。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠開始準備備份線的接入。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "22:55 之前，我把能播的接入備份素材線。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "23:00 閉幕切換的時候，這些東西會出現在每一個看直播的螢幕上。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "不完整。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "但至少有人會看到。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "至少——明天沒有人能說什麼都沒發生過。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在她旁邊。看著她的手指在備份線的接口上動作。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有怪他。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有說「你怎麼想不起來」。沒有說「就差你一個」。沒有說任何一句讓他更難受的話。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她只是在做她能做的最後一步。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我記得。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）「不要只⋯⋯」", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）「孩子看見了。」", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）濕的外套。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）相機的快門聲。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我一定見過全部。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我只是——", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）——還沒有想起來。", background: Background.Chapter_6_Ch6_Act12_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:50。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "備份線接通了。能播放的檔案被排進了佇列。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三個紅色的檔案還鎖在螢幕上方。安靜的。完整的。等著一把還沒有成形的鑰匙。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言看著那三個檔案。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他知道答案在他腦子裡。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他知道它在。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但他碰不到。", background: Background.Chapter_6_Ch6_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "就像隔著一扇鎖住的門，看見裡面有光。", background: Background.Chapter_6_Ch6_Act12_S0 },
];
